#include <stdio.h>
#include <stdlib.h>
typedef struct Node {
    int data;
    struct Node* next;
} Node;
typedef struct Stack {
    Node* top;
} Stack;
void push(Stack* stack, int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->data = data;
    newNode->next = stack->top;
    stack->top = newNode;
}
int pop(Stack* stack) {
    if (stack->top == NULL) {
        printf("Stack is empty\n");
        return -1;
    }
    int data = stack->top->data;
    Node* temp = stack->top;
    stack->top = stack->top->next;
    free(temp);
    return data;
}
int peek(Stack* stack) {
    if (stack->top == NULL) {
        printf("Stack is empty\n");
        return -1;
    }
    return stack->top->data;
}
int isEmpty(Stack* stack) {
    return stack->top == NULL;
}
typedef struct Queue {
    Stack* stack1;
    Stack* stack2;
} Queue;
void queuePush(Queue* queue, int data) {
    push(queue->stack1, data);
}
int queuePop(Queue* queue) {
    if (isEmpty(queue->stack2)) {
        while (!isEmpty(queue->stack1)) {
            push(queue->stack2, pop(queue->stack1));
        }
    }
    return pop(queue->stack2);
}
int queuePeek(Queue* queue) {
    if (isEmpty(queue->stack2)) {
        while (!isEmpty(queue->stack1)) {
            push(queue->stack2, pop(queue->stack1));
        }
    }
    return peek(queue->stack2);
}
int queueIsEmpty(Queue* queue) {
    return isEmpty(queue->stack1) && isEmpty(queue->stack2);
}
int main() {
    Queue* queue = (Queue*) malloc(sizeof(Queue));
    queue->stack1 = (Stack*) malloc(sizeof(Stack));
    queue->stack2 = (Stack*) malloc(sizeof(Stack));
    queue->stack1->top = NULL;
    queue->stack2->top = NULL;
    // Test the queue
    queuePush(queue, 4);
    queuePush(queue, 8);
    printf("%d\n", queuePop(queue)); // prints 4
    printf("%d\n", queuePeek(queue)); // prints 8
    printf("%d\n", queueIsEmpty(queue)); // prints 0
    return 0;
}

