import java.util.Stack;
public class StackQueue {
    private Stack<Integer> st1, st2;
    public StackQueue() {
        st1 = new Stack<>();
        st2 = new Stack<>();
    }
    public void push(int x) {
        while (!st1.isEmpty()) {
            st2.push(st1.pop());
        }
        st1.push(x);
        while (!st2.isEmpty()) {
            st1.push(st2.pop());
        }
    }
    public int pop() {
        if (st1.isEmpty()) {
            System.out.println("Stack is empty");
            return -1;
        }
        return st1.pop();
    }
    public int peek() {
        if (st1.isEmpty()) {
            System.out.println("Stack is empty");
            return -1;
        }
        return st1.peek();
    }
    public boolean isEmpty() {
        return st1.isEmpty();
    }
}

